const item = $input.first().json;
const execution = item.execution || {};
const workflow = item.workflow || {};
const triggerData = execution.error || {};
const message = typeof triggerData.message === 'string' ? triggerData.message : '';
let failureClass = 'unknown';
if (/timeout|econn|network|socket/i.test(message)) failureClass = 'transport';
else if (/401|403|auth|unauthorized|forbidden/i.test(message)) failureClass = 'auth';
else if (/schema|validation|json/i.test(message)) failureClass = 'validation';
return [{
  json: {
    failureClass,
    failureReason: message || 'Unhandled workflow error',
    workflowName: workflow.name || 'unknown',
    workflowId: workflow.id || '',
    executionId: execution.id || '',
    loggedAt: new Date().toISOString()
  }
}];
